import{_ as o,o as a,c as e,a2 as r}from"./chunks/framework.BQ1gajhD.js";const h=JSON.parse('{"title":"静心斋","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/beihai/jingxinzhai.md","filePath":"landmarks/beihai/jingxinzhai.md","lastUpdated":1784720050000}'),l={name:"landmarks/beihai/jingxinzhai.md"};function n(i,t,s,g,u,d){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="静心斋" tabindex="-1">静心斋 <a class="header-anchor" href="#静心斋" aria-label="Permalink to &quot;静心斋&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1773735968626-e78606a37041?w=1200&amp;q=80" alt="静心斋"></p><blockquote><p>园中有园，小中见大——一泓池水、几叠假山、数座亭台，乾隆把整座江南的精致，都装进了这座&quot;小花园&quot;。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><strong>静心斋</strong>位于北海北岸东端，是一座藏于皇家大园之中的<strong>小型精致园林</strong>，素有&quot;<strong>乾隆小花园</strong>&quot;和&quot;<strong>园中之园</strong>&quot;之美誉。它始建于<strong>清乾隆年间</strong>，原名**&quot;镜清斋&quot;**，取&quot;明镜止水、清净无尘&quot;之意，后改称&quot;静心斋&quot;。</p><p>静心斋原本是<strong>皇太子读书静养</strong>之处，规模虽小，却布局精妙：亭台楼阁、假山池沼、曲廊花窗一应俱全，在方寸之间营造出曲折幽深、步移景异的江南园林意境。它是北海公园内<strong>保存最完整、最精致</strong>的一处园中之园，也是中国古典造园艺术&quot;小中见大&quot;的典范之作。</p><p>静心斋之妙，在于&quot;藏&quot;。它不设宏大的殿宇、不铺开阔的广场，而是以一道粉墙、几重曲廊将自己藏于北海的北岸。若非刻意寻觅，游人多从门前匆匆而过，错过这座咫尺之间的精致世界。这种&quot;隐于市、隐于园&quot;的气质，恰恰与它&quot;静心&quot;之名相合——要读懂它，须先静下心来。</p><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">清乾隆年间</td><td style="text-align:left;">始建，初名&quot;镜清斋&quot;，为皇太子读书静养之所</td></tr><tr><td style="text-align:left;">清代</td><td style="text-align:left;">更名&quot;静心斋&quot;，寓读书治学须先静心之意</td></tr><tr><td style="text-align:left;">1900年</td><td style="text-align:left;">遭八国联军破坏，后修复</td></tr><tr><td style="text-align:left;">当代</td><td style="text-align:left;">作为北海最完整的园中之园对外开放</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>位置</strong></td><td style="text-align:left;">北海北岸东端</td></tr><tr><td style="text-align:left;"><strong>始建</strong></td><td style="text-align:left;">清乾隆年间</td></tr><tr><td style="text-align:left;"><strong>原名</strong></td><td style="text-align:left;">镜清斋（后改&quot;静心斋&quot;）</td></tr><tr><td style="text-align:left;"><strong>功能</strong></td><td style="text-align:left;">皇太子读书静养之所</td></tr><tr><td style="text-align:left;"><strong>格局</strong></td><td style="text-align:left;">亭台、假山、池沼、曲廊俱全的园中之园</td></tr><tr><td style="text-align:left;"><strong>艺术</strong></td><td style="text-align:left;">&quot;小中见大&quot;、步移景异的江南造园手法</td></tr></tbody></table><p>静心斋以<strong>一泓池水</strong>为中心，四周环以亭台楼阁、曲廊水榭。园中<strong>假山</strong>以太湖石叠成，玲珑剔透、洞壑幽深；<strong>池沼</strong>曲水萦绕，游鱼可数；亭台<strong>精巧</strong>雅致，随势而筑，或临水、或倚山、或藏于花木之间。曲折的回廊将各处建筑串联，花窗漏窗移步换景，让人在不过亩许的空间里，体验到山重水复、柳暗花明的无穷变化。</p><p>全园虽无宏大殿宇，却以<strong>精巧取胜</strong>——每一处转角、每一扇花窗、每一叠假山都经过精心推敲，是皇家园林中难得的&quot;小而精&quot;之作，充分体现了乾隆帝对江南园林艺术的钟爱与移植。园中的主体建筑临池而建，是昔日太子读书之所；其后假山之上筑有高阁，可俯瞰全园，是全园的观景制高点。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="从-镜清斋-到-静心斋" tabindex="-1">从&quot;镜清斋&quot;到&quot;静心斋&quot; <a class="header-anchor" href="#从-镜清斋-到-静心斋" aria-label="Permalink to &quot;从&quot;镜清斋&quot;到&quot;静心斋&quot;&quot;">​</a></h3><p>静心斋原名**&quot;镜清斋&quot;**，典出&quot;心如明镜、止水无波&quot;的修身意境，是乾隆为皇太子读书静养而精心营建的别院。乾隆帝一生六下江南，对苏州、杭州等地的私家园林倾心不已，回京后便将江南造园的精髓融入皇家苑囿，镜清斋正是这一审美趣味的结晶。后来此园改称&quot;<strong>静心斋</strong>&quot;，一名之改，更点出读书治学须先&quot;静心&quot;的要义，也与园中清幽绝俗的氛围相得益彰。</p><h3 id="乾隆的-江南情结" tabindex="-1">乾隆的&quot;江南情结&quot; <a class="header-anchor" href="#乾隆的-江南情结" aria-label="Permalink to &quot;乾隆的&quot;江南情结&quot;&quot;">​</a></h3><p>静心斋是乾隆&quot;江南情结&quot;的缩影。这位以风雅自诩的帝王，六次南巡，遍览苏杭名园，每有所钟爱，便命画师图样带回，在北方的皇家园林中仿建。于是北海有了静心斋，颐和园有了谐趣园（仿无锡寄畅园），圆明园更是集江南胜景之大成。静心斋虽小，却是这段&quot;移天缩地&quot;造园史的一个精致注脚——一座皇家别院里，浓缩的是帝王对江南烟雨的无限向往。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>园中之园</strong>：体会在宏大的皇家北海之中，藏着一座玲珑剔透的江南式小园的独特格局。</li><li><strong>太湖石假山</strong>：细看园中叠石假山的玲珑洞壑，钻洞穿谷，是&quot;小中见大&quot;造园手法的精华。</li><li><strong>曲廊花窗</strong>：沿回廊漫步，透过漏窗花窗移步换景，每一框都是一幅画，是拍照的绝佳取景。</li><li><strong>池沼亭台</strong>：临水静坐，看曲水游鱼、亭台倒影，感受皇家&quot;读书处&quot;的清幽与宁静。</li><li><strong>精巧布局</strong>：在亩许之地内体会山重水复、步移景异的空间经营，是古典造园艺术的活教材。</li></ol><h2 id="拍照机位" tabindex="-1">拍照机位 <a class="header-anchor" href="#拍照机位" aria-label="Permalink to &quot;拍照机位&quot;">​</a></h2><ol><li><strong>花窗框景</strong>：透过漏窗、花窗拍摄园内一角，框出一幅现成的&quot;宋画&quot;构图。</li><li><strong>池水倒影</strong>：无风时拍摄亭台假山在水中的倒影，虚实相生，意境幽远。</li><li><strong>曲廊纵深</strong>：利用回廊的纵深与转角，拍出&quot;庭院深深&quot;的层次感。</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li><strong>放慢脚步</strong>：静心斋之美在于&quot;精&quot;与&quot;静&quot;，宜缓行细赏，匆匆而过会错过无数细节。</li><li><strong>留意花窗</strong>：园中漏窗、花窗是取景框，透过它们看园景，别有画意，是拍照的好角度。</li><li><strong>避开人流</strong>：作为精致的园中之园，人少时最能体会其清幽，建议开园或闭园前后前往。</li><li><strong>联游北岸</strong>：静心斋与<a href="/beijing-travel-guide/landmarks/beihai/xitianfanjing.html">西天梵境</a>、<a href="/beijing-travel-guide/landmarks/beihai/jiulongbi.html">九龙壁</a>、<a href="/beijing-travel-guide/landmarks/beihai/wulongting.html">五龙亭</a>同在北海北岸，可沿湖串联游览。</li><li><strong>对比谐趣园</strong>：若游颐和园，可将静心斋与<a href="/beijing-travel-guide/landmarks/summer-palace/xiequ-yuan.html">谐趣园</a>对照欣赏——同为&quot;园中之园&quot;，各具匠心。</li><li><strong>静心品味</strong>：既名&quot;静心&quot;，不妨寻一处亭下小坐，听水观鱼，方不负此园真意。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：静心斋为什么被称为&quot;园中之园&quot;？</strong></p><p>静心斋藏于宏大的北海公园北岸一隅，自成一座独立而完整的小园林，墙内有亭台、假山、池沼、曲廊一应俱全，是大园之中套着小园，故称&quot;园中之园&quot;。它也是北海保存最完整的园中之园。</p><p><strong>Q：静心斋和颐和园的谐趣园有什么关系？</strong></p><p>两者同为乾隆&quot;移天缩地&quot;仿江南名园而建的&quot;园中之园&quot;：静心斋取江南园林的精致曲折，谐趣园则仿无锡寄畅园。它们是乾隆&quot;江南情结&quot;在皇家园林中的一双璧，对照游览趣味盎然。</p><p><strong>Q：静心斋需要另外买票吗？</strong></p><p>静心斋包含在北海公园门票内，无需另行购票（具体以现场公示为准）。它位置偏居北岸东端，旅行团较少涉足，是北海难得的清静去处。</p><hr><p><strong>📍 位置</strong>：北海北岸东端 <strong>⏱️ 建议游览</strong>：约40分钟 <strong>🔗 相邻</strong>：<a href="/beijing-travel-guide/landmarks/beihai/xitianfanjing.html">西天梵境</a>（北岸相邻） <strong>🔗 相邻</strong>：<a href="/beijing-travel-guide/landmarks/beihai/jiulongbi.html">九龙壁</a>、<a href="/beijing-travel-guide/landmarks/beihai/wulongting.html">五龙亭</a>（北岸向西） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/beihai/">北海公园概览</a></p>',33)])])}const b=o(l,[["render",n]]);export{h as __pageData,b as default};
